def solve(v: List[List[int]]):
self.v = v
    self.row = 0
    self.col = 0

    def _advance(self):
    while self.row < len(self.v) and self.col >= len(self.v[self.row]):
    self.row += 1
    self.col = 0

    def next(self) -> int:
    self._advance()
    val = self.v[self.row][self.col]
    self.col += 1
    return val

    def hasNext(self) -> bool:
    self._advance()
    return self.row < len(self.v)

